 1	import * as React from 'react';
 2	
 3	import { Button, Text, TextVariants } from '@patternfly/react-core';
 4	import { PlusCircleIcon } from '@patternfly/react-icons';
 5	
 6	export const AddDeviceButton: React.FC<AddDeviceButtonType> = ({
 7	  disabledMessage,
 8	  id,
 9	  isDisabled,
10	  message,
11	  onClick,
12	}) =>
13	  isDisabled ? (
14	    <Text component={TextVariants.p}>{disabledMessage}</Text>
15	  ) : (
16	    <Button
17	      className="pf-m-link--align-left"
18	      icon={<PlusCircleIcon />}
19	      id={id}
20	      onClick={onClick}
21	      variant="link"
22	    >
23	      {message}
24	    </Button>
25	  );
26	
27	export type AddDeviceButtonType = {
28	  disabledMessage: string;
29	  id: string;
30	  isDisabled: boolean;
31	  message: string;
32	  onClick: () => void;
33	};

